import {
  Autocomplete,
  AutocompleteInput,
  Box,
  Flex,
  Grid,
  Highlight,
  Text,
} from '@tonic-ui/react';
import { isNullish } from '@tonic-ui/utils';
import { ensureString } from 'ensure-type';
import { useCallback, useEffect, useRef, useState } from 'react';
import { fruitItems } from './constants';

// Simulates an async request to a server.
// In a real app, replace with an actual API call.
const fetchItems = (query) => new Promise((resolve) => {
  setTimeout(() => {
    const q = query.trim().toLowerCase();
    resolve(
      q
        ? fruitItems.filter((item) => ensureString(item.label).toLowerCase().includes(q))
        : fruitItems,
    );
  }, 1000);
});

// Simulates an RTK Query generated hook.
// In a real app, replace with the hook generated by createApi:
//
// ```js
// const fruitsApi = createApi({
//   baseQuery: fetchBaseQuery({ baseUrl: '/api' }),
//   endpoints: (builder) => ({
//     searchFruits: builder.query({
//       queryFn: async (q) => {
//         const data = await fetchItems(q);
//         return { data };
//       },
//     }),
//   }),
// });
// export const { useSearchItemsQuery } = fruitsApi;
// ```
const useSearchItemsQuery = (query, { skip = false } = {}) => {
  const [data, setData] = useState(undefined);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (skip) {
      setIsLoading(false);
      return () => {};
    }
    let cancelled = false;
    setIsLoading(true);
    fetchItems(query).then((result) => {
      if (!cancelled) {
        setData(result);
        setIsLoading(false);
      }
    });
    return () => {
      cancelled = true;
    };
  }, [query, skip]);

  return { data, isLoading };
};

/**
 * @param {string | null} searchQuery - null defers the first fetch until the popup opens.
 * @param {number} [delay=300] - 300ms matches the natural pause between keystrokes.
 * @returns {{ data: any[]; isLoading: boolean }}
 */
const useDebouncedSearchItemsQuery = (searchQuery, delay = 300) => {
  const [debouncedQuery, setDebouncedQuery] = useState(searchQuery);
  const prevSearchQueryRef = useRef(searchQuery);

  useEffect(() => {
    const prev = prevSearchQueryRef.current;
    prevSearchQueryRef.current = searchQuery;

    if (isNullish(searchQuery)) {
      setDebouncedQuery(null);
      return () => {};
    }
    // Skip debounce on first open (null → value) — not a typing burst.
    if (isNullish(prev)) {
      setDebouncedQuery(searchQuery);
      return () => {};
    }
    const timer = setTimeout(() => setDebouncedQuery(searchQuery), delay);
    return () => clearTimeout(timer);
  }, [searchQuery, delay]);

  // Replace with your RTK Query hook
  return useSearchItemsQuery(debouncedQuery ?? '', {
    skip: isNullish(debouncedQuery),
  });
};

const App = () => {
  const [searchQuery, setSearchQuery] = useState(null); // null = not yet opened
  const [value, setValue] = useState(null);
  const { data: items = [], isLoading } = useDebouncedSearchItemsQuery(searchQuery);

  const handleOpen = useCallback(() => {
    setSearchQuery((prev) => prev === null ? '' : prev);
  }, []);

  const handleInputChange = useCallback((nextValue) => {
    // Skip re-fetching when closeBehavior="restore" reverts the input to
    // the committed selection — the results haven't changed.
    if (value && nextValue === value.label) {
      return;
    }
    setSearchQuery(nextValue);
  }, [value]);

  const handleChange = useCallback((item) => {
    // `onChange` fires with the selected item, or with `null` on clear (X
    // button or `closeBehavior: 'clear'`). Both paths reset the search query
    // so the next open triggers a fresh fetch via `handleOpen`.
    setValue(item);
    setSearchQuery(null);
  }, []);

  return (
    <Box>
      <Flex fontFamily="mono" mb="4x">
        <Grid
          columnGap="2x"
          rowGap="2x"
          templateColumns="auto 1fr"
        >
          <Text>value:</Text>
          <Text>{JSON.stringify(value)}</Text>
        </Grid>
      </Flex>
      <Autocomplete
        sx={{
          width: 400,
        }}
        autoHighlight
        filterItems={(items) => items} // passthrough
        isClearable
        isLoading={isLoading}
        items={items}
        onChange={handleChange}
        onInputChange={handleInputChange}
        onOpen={handleOpen}
        portalled
        selectOnFocus
        renderInput={(params) => (
          <AutocompleteInput
            {...params}
            placeholder="Search fruits..."
          />
        )}
        renderContent={({ items: filteredItems, renderItems, isLoading }) => {
          if (isLoading) {
            return (
              <Box px="3x" py="2x">Loading...</Box>
            );
          }
          if (filteredItems.length === 0) {
            return (
              <Box px="3x" py="2x">No items</Box>
            );
          }
          return renderItems(filteredItems);
        }}
        renderItem={(item, { inputValue: query }) => (
          <Highlight variant="highlight" query={query}>
            {item.label}
          </Highlight>
        )}
      />
    </Box>
  );
};

export default App;
